     1→import { createStore } from 'zustand/vanilla';
     2→import { useStore } from 'zustand';
     3→
     4→/**
     5→ * Maintenance block types (stored as Uint8 enum).
     6→ */
     7→export const BlockType = {
     8→  PM: 0,          // Preventive Maintenance
     9→  OVERHAUL: 1,    // Major overhaul
    10→  INSPECTION: 2,  // Regular inspection
    11→  REPAIR: 3,      // Unplanned repair
    12→  CLEANING: 4,    // Cleaning/detailing
    13→} as const;
    14→
    15→export type BlockTypeValue = typeof BlockType[keyof typeof BlockType];
    16→
    17→/**
    18→ * Structure of Arrays (SoA) for high-performance schedule data.
    19→ * Pre-allocated TypedArrays for cache-friendly iteration.
    20→ */
    21→export interface ScheduleArrays {
    22→  /** Capacity of pre-allocated arrays */
    23→  capacity: number;
    24→  /** Current number of active blocks */
    25→  count: number;
    26→
    27→  /** Start time in milliseconds (epoch) */
    28→  startTimes: Float64Array;
    29→  /** End time in milliseconds (epoch) */
    30→  endTimes: Float64Array;
    31→  /** Train ID (index into train lookup table) */
    32→  trainIds: Int32Array;
    33→  /** Block type (see BlockType enum) */
    34→  types: Uint8Array;
    35→  /** Track/bay ID for workshop assignment */
    36→  trackIds: Int16Array;
    37→  /** Status flags: bit 0 = selected, bit 1 = dragging, bit 2 = conflict */
    38→  flags: Uint8Array;
    39→}
    40→
    41→export interface SimulationState {
    42→  schedule: ScheduleArrays;
    43→  /** Map of train index -> train metadata */
    44→  trainLookup: Map<number, { id: string; name: string; fleet: string }>;
    45→  /** Set of currently selected block indices */
    46→  selectedBlocks: Set<number>;
    47→  /** Index of block being dragged, or -1 */
    48→  draggingBlock: number;
    49→}
    50→
    51→export interface SimulationActions {
    52→  /** Initialize schedule arrays with capacity */
    53→  initializeSchedule: (capacity: number) => void;
    54→  /** Add a schedule block, returns index */
    55→  addBlock: (
    56→    startTime: number,
    57→    endTime: number,
    58→    trainId: number,
    59→    type: BlockTypeValue,
    60→    trackId: number
    61→  ) => number;
    62→  /** Update block times (for drag operations) */
    63→  updateBlockTimes: (index: number, startTime: number, endTime: number) => void;
    64→  /** Select/deselect a block */
    65→  toggleBlockSelection: (index: number) => void;
    66→  /** Clear all selections */
    67→  clearSelection: () => void;
    68→  /** Start dragging a block */
    69→  startDrag: (index: number) => void;
    70→  /** Stop dragging */
    71→  stopDrag: () => void;
    72→}
    73→
    74→const DEFAULT_CAPACITY = 100000;
    75→
    76→function createEmptySchedule(capacity: number): ScheduleArrays {
    77→  return {
    78→    capacity,
    79→    count: 0,
    80→    startTimes: new Float64Array(capacity),
    81→    endTimes: new Float64Array(capacity),
    82→    trainIds: new Int32Array(capacity),
    83→    types: new Uint8Array(capacity),
    84→    trackIds: new Int16Array(capacity),
    85→    flags: new Uint8Array(capacity),
    86→  };
    87→}
    88→
    89→export const simulationStore = createStore<SimulationState & SimulationActions>((set, get) => ({
    90→  schedule: createEmptySchedule(DEFAULT_CAPACITY),
    91→  trainLookup: new Map(),
    92→  selectedBlocks: new Set(),
    93→  draggingBlock: -1,
    94→
    95→  initializeSchedule: (capacity: number) => {
    96→    set({ schedule: createEmptySchedule(capacity) });
    97→  },
    98→
    99→  addBlock: (startTime, endTime, trainId, type, trackId) => {
   100→    const { schedule } = get();
   101→    const index = schedule.count;
   102→
   103→    if (index >= schedule.capacity) {
   104→      console.warn('Schedule capacity exceeded');
   105→      return -1;
   106→    }
   107→
   108→    schedule.startTimes[index] = startTime;
   109→    schedule.endTimes[index] = endTime;
   110→    schedule.trainIds[index] = trainId;
   111→    schedule.types[index] = type;
   112→    schedule.trackIds[index] = trackId;
   113→    schedule.flags[index] = 0;
   114→
   115→    set({ schedule: { ...schedule, count: index + 1 } });
   116→    return index;
   117→  },
   118→
   119→  updateBlockTimes: (index: number, startTime: number, endTime: number) => {
   120→    const { schedule } = get();
   121→    if (index < 0 || index >= schedule.count) return;
   122→
   123→    schedule.startTimes[index] = startTime;
   124→    schedule.endTimes[index] = endTime;
   125→    // Trigger update without reallocating arrays
   126→    set({ schedule: { ...schedule } });
   127→  },
   128→
   129→  toggleBlockSelection: (index: number) => {
   130→    const { selectedBlocks, schedule } = get();
   131→    const newSelection = new Set(selectedBlocks);
   132→
   133→    if (newSelection.has(index)) {
   134→      newSelection.delete(index);
   135→      schedule.flags[index] &= ~1; // Clear selected bit
   136→    } else {
   137→      newSelection.add(index);
   138→      schedule.flags[index] |= 1; // Set selected bit
   139→    }
   140→
   141→    set({ selectedBlocks: newSelection });
   142→  },
   143→
   144→  clearSelection: () => {
   145→    const { selectedBlocks, schedule } = get();
   146→    for (const index of selectedBlocks) {
   147→      schedule.flags[index] &= ~1;
   148→    }
   149→    set({ selectedBlocks: new Set() });
   150→  },
   151→
   152→  startDrag: (index: number) => {
   153→    const { schedule } = get();
   154→    if (index >= 0 && index < schedule.count) {
   155→      schedule.flags[index] |= 2; // Set dragging bit
   156→      set({ draggingBlock: index });
   157→    }
   158→  },
   159→
   160→  stopDrag: () => {
   161→    const { draggingBlock, schedule } = get();
   162→    if (draggingBlock >= 0) {
   163→      schedule.flags[draggingBlock] &= ~2; // Clear dragging bit
   164→    }
   165→    set({ draggingBlock: -1 });
   166→  },
   167→}));
   168→
   169→/** React hook for simulation state */
   170→export function useSimulation<T>(selector: (state: SimulationState & SimulationActions) => T): T {
   171→  return useStore(simulationStore, selector);
   172→}
   173→
   174→/** Direct access for non-React contexts */
   175→export const getSimulationState = simulationStore.getState;
   176→export const subscribeSimulation = simulationStore.subscribe;
   177→

