      simulationStore.getState().updateBlockTimes(0, newStart, newEnd);

      const { schedule } = simulationStore.getState();
      expect(schedule.startTimes[0]).toBe(newStart);
      expect(schedule.endTimes[0]).toBe(newEnd);
    });

    it('should not crash on invalid index', () => {
      const state = simulationStore.getState();
      expect(() => state.updateBlockTimes(-1, 0, 0)).not.toThrow();
      expect(() => state.updateBlockTimes(999, 0, 0)).not.toThrow();
    });
  });

  describe('selection', () => {
    it('should toggle block selection', () => {
      const state = simulationStore.getState();
      const now = Date.now();
      state.addBlock(now, now + 1000, 1, BlockType.PM, 0);

      simulationStore.getState().toggleBlockSelection(0);
      expect(simulationStore.getState().selectedBlocks.has(0)).toBe(true);
      expect(simulationStore.getState().schedule.flags[0] & 1).toBe(1);

      simulationStore.getState().toggleBlockSelection(0);
      expect(simulationStore.getState().selectedBlocks.has(0)).toBe(false);
      expect(simulationStore.getState().schedule.flags[0] & 1).toBe(0);
    });

    it('should clear all selections', () => {
      const state = simulationStore.getState();
      const now = Date.now();
      state.addBlock(now, now + 1000, 1, BlockType.PM, 0);
      state.addBlock(now + 2000, now + 3000, 2, BlockType.PM, 0);

      simulationStore.getState().toggleBlockSelection(0);
      simulationStore.getState().toggleBlockSelection(1);
      simulationStore.getState().clearSelection();

      const { selectedBlocks, schedule } = simulationStore.getState();
      expect(selectedBlocks.size).toBe(0);
      expect(schedule.flags[0] & 1).toBe(0);
      expect(schedule.flags[1] & 1).toBe(0);
    });
  });

  describe('drag operations', () => {
    it('should start and stop drag', () => {
      const state = simulationStore.getState();
      const now = Date.now();
      state.addBlock(now, now + 1000, 1, BlockType.PM, 0);

      simulationStore.getState().startDrag(0);
      expect(simulationStore.getState().draggingBlock).toBe(0);
      expect(simulationStore.getState().schedule.flags[0] & 2).toBe(2);

      simulationStore.getState().stopDrag();
      expect(simulationStore.getState().draggingBlock).toBe(-1);
      expect(simulationStore.getState().schedule.flags[0] & 2).toBe(0);
    });
  });
});

import { describe, it, expect, beforeEach } from 'vitest';
import { viewportStore } from '../store/viewportStore';

describe('viewportStore', () => {
  beforeEach(() => {
    viewportStore.setState({
      scale: 0.00001,
      offsetX: 0,
      offsetY: 0,
      lod: 1,
    });
  });

  describe('setScale', () => {
    it('should set scale within bounds', () => {
      viewportStore.getState().setScale(0.0001);
      expect(viewportStore.getState().scale).toBe(0.0001);
    });

    it('should clamp scale to minimum', () => {
      viewportStore.getState().setScale(0.0000000001);
      expect(viewportStore.getState().scale).toBe(0.0000001);
    });

    it('should clamp scale to maximum', () => {
      viewportStore.getState().setScale(1);
      expect(viewportStore.getState().scale).toBe(0.001);
    });
  });

  describe('pan', () => {
    it('should update offset when panning', () => {
      viewportStore.getState().pan(100, 50);
      const { offsetX, offsetY } = viewportStore.getState();
      expect(offsetX).toBe(100);
      expect(offsetY).toBe(50);
    });

    it('should accumulate pan offsets', () => {
      viewportStore.getState().pan(100, 50);
      viewportStore.getState().pan(-30, 20);
      const { offsetX, offsetY } = viewportStore.getState();
      expect(offsetX).toBe(70);
      expect(offsetY).toBe(70);
    });
  });

  describe('zoom', () => {
    it('should zoom in', () => {
      const initialScale = viewportStore.getState().scale;
      viewportStore.getState().zoom(2, 0, 0);
      expect(viewportStore.getState().scale).toBeGreaterThan(initialScale);
    });

    it('should zoom out', () => {
      const initialScale = viewportStore.getState().scale;
      viewportStore.getState().zoom(0.5, 0, 0);
      expect(viewportStore.getState().scale).toBeLessThan(initialScale);
    });
  });

  describe('setDimensions', () => {
    it('should set viewport dimensions', () => {
      viewportStore.getState().setDimensions(1920, 1080);
      const { width, height } = viewportStore.getState();
      expect(width).toBe(1920);
      expect(height).toBe(1080);
    });
  });

  describe('LOD calculations', () => {
    it('should be LOD 0 at very small scale', () => {
      viewportStore.setState({ lod: 0 });
      viewportStore.getState().setScale(0.0000001);
      expect(viewportStore.getState().lod).toBe(0);
    });

    it('should transition to LOD 1 when zooming in from LOD 0', () => {
      viewportStore.setState({ lod: 0, scale: 0.0000001 });
      viewportStore.getState().setScale(0.0001);
      expect(viewportStore.getState().lod).toBe(1);
    });

    it('should transition to LOD 2 when zooming in more', () => {
      viewportStore.setState({ lod: 1, scale: 0.0001 });
      viewportStore.getState().setScale(0.001);
      expect(viewportStore.getState().lod).toBe(2);
    });

    it('should have hysteresis to prevent oscillation', () => {
      viewportStore.setState({ lod: 1 });
      const threshold = 0.1 / 3600000;
      viewportStore.getState().setScale(threshold);
      const lodAtThreshold = viewportStore.getState().lod;
      expect(lodAtThreshold).toBe(1);
    });
  });

  describe('setLod', () => {
    it('should manually set LOD level', () => {
      viewportStore.getState().setLod(2);
      expect(viewportStore.getState().lod).toBe(2);
      viewportStore.getState().setLod(0);
      expect(viewportStore.getState().lod).toBe(0);
    });
  });
});

