    19→  onReady?: (renderer: FractalRenderer) => void;
    20→}
    21→
    22→export function PixiCanvas({ debug = false, onReady }: PixiCanvasProps) {
    23→  const containerRef = useRef<HTMLDivElement>(null);
    24→  const rendererRef = useRef<FractalRenderer | null>(null);
    25→  const cleanupScrollerRef = useRef<(() => void) | null>(null);
    26→
    27→  /**
    28→   * Initialize PixiJS when component mounts.
    29→   */
    30→  const initRenderer = useCallback(async () => {
    31→    const container = containerRef.current;
    32→    if (!container) return;
    33→
    34→    // Create renderer with config
    35→    const renderer = new FractalRenderer({ debug });
    36→    rendererRef.current = renderer;
    37→
    38→    try {
    39→      await renderer.init(container);
    40→
    41→      // Attach virtual scroller events
    42→      cleanupScrollerRef.current = attachScrollerEvents(container);
    43→
    44→      // Notify parent
    45→      onReady?.(renderer);
    46→    } catch (error) {
    47→      console.error('[PixiCanvas] Failed to initialize:', error);
    48→    }
    49→  }, [debug, onReady]);
    50→
    51→  /**
    52→   * Handle container resize.
    53→   */
    54→  const handleResize = useCallback(() => {
    55→    const container = containerRef.current;
    56→    const renderer = rendererRef.current;
    57→
    58→    if (!container || !renderer || !renderer.isReady()) return;
    59→
    60→    const { width, height } = container.getBoundingClientRect();
    61→    renderer.resize(width, height);
    62→  }, []);
    63→
    64→  /**
    65→   * Setup and cleanup effects.
    66→   */
    67→  useEffect(() => {
    68→    // Initialize renderer
    69→    initRenderer();
    70→
    71→    // Setup resize observer
    72→    const container = containerRef.current;
    73→    let resizeObserver: ResizeObserver | null = null;
    74→
    75→    if (container) {
    76→      resizeObserver = new ResizeObserver(() => {
    77→        handleResize();
    78→      });
    79→      resizeObserver.observe(container);
    80→    }
    81→
    82→    // Cleanup on unmount
    83→    return () => {
    84→      if (resizeObserver) {
    85→        resizeObserver.disconnect();
    86→      }
    87→
    88→      if (cleanupScrollerRef.current) {
    89→        cleanupScrollerRef.current();
    90→        cleanupScrollerRef.current = null;
    91→      }
    92→
    93→      if (rendererRef.current) {
    94→        rendererRef.current.destroy();
    95→        rendererRef.current = null;
    96→      }
    97→    };
    98→  }, [initRenderer, handleResize]);
