import { Container, Graphics, Text, TextStyle } from 'pixi.js';
import { getSimulationState, BlockType, type BlockTypeValue } from '../../engine/store/simulationStore';
import { getViewportState } from '../../engine/store/viewportStore';
import { batchTimeToPixel } from '../../engine/physics/coordinateTransformer';

/**
 * CapsulesLayer - LOD 2 renderer for close zoom levels.
 *
 * Renders schedule blocks as detailed capsules with:
 * - Rounded rectangle shapes with gradients
 * - Text labels showing block type and train info
 * - Visual state indicators (selection, drag, conflict)
 *
 * Performance: Uses object pooling for Text objects and
 * view frustum culling to minimize draw calls.
 */

export interface CapsulesConfig {
  /** Row height in pixels */
  rowHeight: number;
  /** Number of train rows */
  numRows: number;
  /** Minimum capsule width to render text */
  minTextWidth: number;
  /** Capsule height as fraction of row height */
  capsuleHeightRatio: number;
  /** Corner radius for capsules */
  cornerRadius: number;
  /** Font size for block labels */
  fontSize: number;
}

const DEFAULT_CONFIG: CapsulesConfig = {
  rowHeight: 40,
  numRows: 128,
  minTextWidth: 60,
  capsuleHeightRatio: 0.75,
  cornerRadius: 6,
  fontSize: 11,
};

/** Colors for each maintenance type */
const TYPE_COLORS: Record<BlockTypeValue, number> = {
  [BlockType.PM]: 0x3ddc84,
  [BlockType.OVERHAUL]: 0xff6b35,
  [BlockType.INSPECTION]: 0x4ecdc4,
  [BlockType.REPAIR]: 0xd62828,
  [BlockType.CLEANING]: 0x9b59b6,
};

/** Labels for maintenance types */
const TYPE_LABELS: Record<BlockTypeValue, string> = {
  [BlockType.PM]: 'PM',
  [BlockType.OVERHAUL]: 'OVH',
  [BlockType.INSPECTION]: 'INS',
  [BlockType.REPAIR]: 'REP',
  [BlockType.CLEANING]: 'CLN',
};

/** Pre-allocated arrays for batch transform */
const MAX_VISIBLE_BLOCKS = 2000;
const tempX = new Float32Array(MAX_VISIBLE_BLOCKS);
const tempWidth = new Float32Array(MAX_VISIBLE_BLOCKS);

/** Text style cache (shared across all text objects) */
let sharedTextStyle: TextStyle | null = null;

function getTextStyle(fontSize: number): TextStyle {
  if (!sharedTextStyle || sharedTextStyle.fontSize !== fontSize) {
    sharedTextStyle = new TextStyle({
      fontFamily: 'Inter, system-ui, sans-serif',
      fontSize,
      fontWeight: '500',
      fill: 0xffffff,
      align: 'left',
    });
  }
  return sharedTextStyle;
}

export class CapsulesLayer {
  private container: Container;
  private capsulesGraphics: Graphics;
  private textContainer: Container;
  private config: CapsulesConfig;
  private isDirty = true;

  /** Object pool for Text instances */
  private textPool: Text[] = [];
  private activeTextCount = 0;

  /** Visible block indices for current frame */
  private visibleIndices: number[] = [];

  constructor(config: Partial<CapsulesConfig> = {}) {
    this.config = { ...DEFAULT_CONFIG, ...config };
    this.container = new Container();
    this.container.label = 'capsules-layer';

    this.capsulesGraphics = new Graphics();
    this.capsulesGraphics.label = 'capsules-graphics';
    this.container.addChild(this.capsulesGraphics);

    this.textContainer = new Container();
    this.textContainer.label = 'capsules-text';
    this.container.addChild(this.textContainer);

    this.initTextPool();
  }

  /**
   * Pre-allocate Text objects for pooling.
   */
  private initTextPool(): void {
    const poolSize = 500;
    const style = getTextStyle(this.config.fontSize);

    for (let i = 0; i < poolSize; i++) {
      const text = new Text({ text: '', style });
      text.visible = false;
      this.textPool.push(text);
      this.textContainer.addChild(text);
    }
  }

  /**
   * Get a Text object from the pool.
   */
  private acquireText(): Text | null {
    if (this.activeTextCount >= this.textPool.length) {
      return null;
    }
    const text = this.textPool[this.activeTextCount];
    text.visible = true;
    this.activeTextCount++;
    return text;
  }

  /**
   * Return all Text objects to the pool.
   */
  private releaseAllText(): void {
    for (let i = 0; i < this.activeTextCount; i++) {
      this.textPool[i].visible = false;
    }
    this.activeTextCount = 0;
  }

  /**
   * Get the container for adding to stage.
   */
  getContainer(): Container {
    return this.container;
  }

  /**
   * Mark layer as needing recalculation.
   */
  markDirty(): void {
    this.isDirty = true;
  }

  /**
   * Update and render the capsules.
   */
  update(): void {
    if (!this.isDirty) return;

    this.cullVisibleBlocks();
    this.renderCapsules();
    this.isDirty = false;
  }

  /**
   * Determine which blocks are visible in the current viewport.
   */
  private cullVisibleBlocks(): void {
    const { schedule } = getSimulationState();
    const viewport = getViewportState();
    const { numRows, rowHeight } = this.config;

    this.visibleIndices = [];

    if (schedule.count === 0) return;

    const { originTime, scale, offsetX, width, height, offsetY } = viewport;
    const viewStartTime = (0 - offsetX) / scale + originTime;
    const viewEndTime = (width - offsetX) / scale + originTime;

    const viewStartRow = Math.max(0, Math.floor(-offsetY / rowHeight));
    const viewEndRow = Math.min(numRows, Math.ceil((height - offsetY) / rowHeight));

    for (let i = 0; i < schedule.count && this.visibleIndices.length < MAX_VISIBLE_BLOCKS; i++) {
      const blockStart = schedule.startTimes[i];
      const blockEnd = schedule.endTimes[i];
      const trainId = schedule.trainIds[i];

      if (blockEnd < viewStartTime || blockStart > viewEndTime) continue;
      if (trainId < viewStartRow || trainId > viewEndRow) continue;

      this.visibleIndices.push(i);
    }
  }

  /**
   * Render visible capsules with text labels.
   */
  private renderCapsules(): void {
    const { schedule, trainLookup } = getSimulationState();
    const viewport = getViewportState();
    const { rowHeight, minTextWidth, capsuleHeightRatio, cornerRadius } = this.config;

    this.capsulesGraphics.clear();
    this.releaseAllText();

    if (this.visibleIndices.length === 0) return;

    const count = this.visibleIndices.length;

    const visibleStartTimes = new Float64Array(count);
    const visibleEndTimes = new Float64Array(count);

    for (let i = 0; i < count; i++) {
      const idx = this.visibleIndices[i];
      visibleStartTimes[i] = schedule.startTimes[idx];
      visibleEndTimes[i] = schedule.endTimes[idx];
    }

    batchTimeToPixel(visibleStartTimes, visibleEndTimes, count, tempX, tempWidth);

    const capsuleHeight = rowHeight * capsuleHeightRatio;
    const yOffset = (rowHeight - capsuleHeight) / 2;

    for (let i = 0; i < count; i++) {
      const idx = this.visibleIndices[i];
      const blockType = schedule.types[idx] as BlockTypeValue;
      const trainId = schedule.trainIds[idx];
      const flags = schedule.flags[idx];

      const x = tempX[i];
      const width = Math.max(4, tempWidth[i]);
      const y = trainId * rowHeight + yOffset + viewport.offsetY;

      if (x + width < 0 || x > viewport.width) continue;

      const isSelected = (flags & 1) !== 0;
      const isDragging = (flags & 2) !== 0;
      const hasConflict = (flags & 4) !== 0;

      let baseColor = TYPE_COLORS[blockType];
      let alpha = 1.0;

      if (hasConflict) {
        baseColor = 0xff0000;
        alpha = 0.9;
      } else if (isDragging) {
        alpha = 0.6;
      }

      // Draw shadow
      this.capsulesGraphics.roundRect(x + 2, y + 2, width, capsuleHeight, cornerRadius);
      this.capsulesGraphics.fill({ color: 0x000000, alpha: 0.2 });

      // Draw main capsule
      this.capsulesGraphics.roundRect(x, y, width, capsuleHeight, cornerRadius);
      this.capsulesGraphics.fill({ color: baseColor, alpha });

      // Draw border
      this.capsulesGraphics.roundRect(x, y, width, capsuleHeight, cornerRadius);
      this.capsulesGraphics.stroke({
        width: isSelected ? 2 : 1,
        color: isSelected ? 0xffffff : this.darkenColor(baseColor, 0.3),
        alpha: isSelected ? 1 : 0.5,
      });

      // Draw highlight line at top
      this.capsulesGraphics.moveTo(x + cornerRadius, y + 2);
      this.capsulesGraphics.lineTo(x + width - cornerRadius, y + 2);
      this.capsulesGraphics.stroke({ width: 1, color: 0xffffff, alpha: 0.3 });

      // Add text label if capsule is wide enough
      if (width >= minTextWidth) {
        const text = this.acquireText();
        if (text) {
          const typeLabel = TYPE_LABELS[blockType];
          const trainInfo = trainLookup.get(trainId);
          const trainName = trainInfo ? trainInfo.id : `T${trainId}`;
          text.text = `${typeLabel} - ${trainName}`;
          text.x = x + 6;
          text.y = y + (capsuleHeight - text.height) / 2;

          // Clip text if it exceeds capsule width
          if (text.width > width - 12) {
            text.text = typeLabel;
          }
        }
      }
    }
  }

  /**
   * Darken a color by a factor (0-1).
   */
  private darkenColor(color: number, factor: number): number {
    const r = ((color >> 16) & 0xff) * (1 - factor);
    const g = ((color >> 8) & 0xff) * (1 - factor);
    const b = (color & 0xff) * (1 - factor);
    return (Math.round(r) << 16) | (Math.round(g) << 8) | Math.round(b);
  }

  /**
   * Get block index at screen position, or -1 if none.
   */
  hitTest(screenX: number, screenY: number): number {
    const { schedule } = getSimulationState();
    const viewport = getViewportState();
    const { rowHeight, capsuleHeightRatio } = this.config;

    const capsuleHeight = rowHeight * capsuleHeightRatio;
    const yOffset = (rowHeight - capsuleHeight) / 2;

    const row = Math.floor((screenY - viewport.offsetY) / rowHeight);

    for (let i = 0; i < this.visibleIndices.length; i++) {
      const idx = this.visibleIndices[i];

      if (schedule.trainIds[idx] !== row) continue;

      const x = tempX[i];
      const width = tempWidth[i];
      const y = row * rowHeight + yOffset + viewport.offsetY;

      if (
        screenX >= x &&
        screenX <= x + width &&
        screenY >= y &&
        screenY <= y + capsuleHeight
      ) {
        return idx;
      }
    }

    return -1;
  }

  /**
   * Resize the layer.
   */
  resize(_width: number, _height: number): void {
    this.markDirty();
  }

  /**
   * Destroy the layer and release resources.
   */
  destroy(): void {
    this.capsulesGraphics.destroy();
    for (const text of this.textPool) {
      text.destroy();
    }
    this.textPool = [];
    this.textContainer.destroy({ children: true });
    this.container.destroy({ children: true });
    this.visibleIndices = [];
    sharedTextStyle = null;
  }
}

