import { test, expect } from '@playwright/test';

/**
 * Smoke tests - Verify app renders without errors.
 * These tests MUST pass before any feature can be marked as done.
 */
test.describe('Smoke Tests', () => {
  test('app renders without console errors', async ({ page }) => {
    const errors: string[] = [];

    // Capture console errors
    page.on('console', (msg) => {
      if (msg.type() === 'error') {
        errors.push(msg.text());
      }
    });

    // Capture page errors (uncaught exceptions)
    page.on('pageerror', (error) => {
      errors.push(`Page Error: ${error.message}`);
    });

    // Navigate to the app
    await page.goto('/');

    // Wait for app to load
    await page.waitForLoadState('networkidle');

    // Wait a bit for React/PixiJS to initialize
    await page.waitForTimeout(2000);

    // Check for critical elements
    await expect(page.locator('body')).toBeVisible();

    // Report errors if any
    if (errors.length > 0) {
      console.log('Console errors found:');
      errors.forEach((e, i) => console.log(`  ${i + 1}. ${e}`));
    }

    // Fail if there are errors
    expect(errors, `Found ${errors.length} console errors`).toHaveLength(0);
  });

  test('PixiJS canvas initializes', async ({ page }) => {
    const errors: string[] = [];

    page.on('console', (msg) => {
      if (msg.type() === 'error') {
        errors.push(msg.text());
      }
    });

    page.on('pageerror', (error) => {
      errors.push(`Page Error: ${error.message}`);
    });

    await page.goto('/');
    await page.waitForLoadState('networkidle');
    await page.waitForTimeout(2000);

    // Check that canvas element exists
    const canvas = page.locator('canvas');
    await expect(canvas).toBeVisible();

    // Verify no errors during canvas init
    expect(errors, `Canvas init errors: ${errors.join(', ')}`).toHaveLength(0);
  });

  test('header displays correctly', async ({ page }) => {
    await page.goto('/');
    await page.waitForLoadState('networkidle');

    // Check header elements
    await expect(page.getByRole('heading', { name: /MMS Fractal Planner/i })).toBeVisible();
    await expect(page.getByText(/LOD/)).toBeVisible();
  });
});

